Example: Regression on Diamonds
Instead of mtcars, let’s look at predicting diamond prices.
library(kerasnip)
library(tidymodels)
library(keras3)

# 1. Define blocks
input_block &lt;- function(model, input_shape) {
  keras_model_sequential(input_shape = input_shape)
}

dense_block &lt;- function(model, units = 128) {
  model |&gt; layer_dense(units = units, activation = "relu")
}

output_block &lt;- function(model) {
  model |&gt; layer_dense(units = 1)
}

# 2. Create Spec
create_keras_sequential_spec(
  model_name = "diamond_mlp",
  layer_blocks = list(
    input = input_block,
    body = dense_block,
    output = output_block
  ),
  mode = "regression"
)
